def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def check_no_solution(nums, target):
    if not nums:
        return True
    return all(nums[i] + nums[j] != target for i in range(len(nums)) for j in range(i + 1, len(nums)))

def check_indices_not_reused(left, right):
    return left != right

# Example usage
nums = [1, 2, 3, 4, 5]
target = 9
result = solve(nums, target)
if result != (-1, -1):
    left, right = result
    assert check_indices_not_reused(left, right), "Indices should not be reused."
else:
    assert check_no_solution(nums, target), "There should be no solution."
